import{_ as n,o as r,c as t,a2 as a}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"F14: 負債結構與償債壓力測試 - 投資研究員 (finance-investment-researcher) 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3189_景碩/20260423/F14_負債結構與償債壓力測試_投資研究員_審計報告.md","filePath":"審計報告庫/財務審計/3189_景碩/20260423/F14_負債結構與償債壓力測試_投資研究員_審計報告.md"}'),o={name:"審計報告庫/財務審計/3189_景碩/20260423/F14_負債結構與償債壓力測試_投資研究員_審計報告.md"};function i(s,e,l,_,c,d){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="f14-負債結構與償債壓力測試-投資研究員-finance-investment-researcher-審計報告" tabindex="-1">F14: 負債結構與償債壓力測試 - 投資研究員 (finance-investment-researcher) 審計報告 <a class="header-anchor" href="#f14-負債結構與償債壓力測試-投資研究員-finance-investment-researcher-審計報告" aria-label="Permalink to &quot;F14: 負債結構與償債壓力測試 - 投資研究員 (finance-investment-researcher) 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>負債比率與利息覆蓋倍數為何？債務到期分佈是否集中於短期？在高利率環境下的利息支出承受度為何？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p><strong>評級：A (良)</strong>。根據截至 2025 年 Q4 (2025 年報) 最新公開數據，景碩合併負債比 48.27% 屬載板產業中等水位；利息保障倍數 (ICR) 為 6.82 倍，財務結構具備基本安全緩衝。惟短期借款佔總有息債務 21.4%，且 2025 年全年利息支出達 3.91 億元，在高利率延續環境下仍需關注槓桿變動。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>負債比演變 (2022→2025)</strong>：2022 年報 46.54% (33,816/72,633 百萬) → 2023 年報約 49% → 2024 年報約 48% → 2025 年報 48.27% (38,600 百萬/79,973 百萬)，長期穩定於 46-49% 區間，未見激進擴張。</li><li><strong>利息保障倍數 (ICR)</strong>：2025 全年 EBIT 26.70 億 / 利息費用 3.91 億 = 6.82 倍，高於安全閾值 3 倍，但低於高品質標準 15 倍。2023 年產業低谷期 ICR 一度降至 1.5-2 倍區間，2025 年隨營運復甦明顯改善。</li><li><strong>債務到期結構</strong>：短期借款 30.53 億 (佔總有息債務 14.25 億的 21.4%) + 長期借款 111.97 億。一年內到期長短期債務約 33 億，對比期末現金 122.81 億，短期流動性缺口比值 27.1% &gt; 20%，屬可控但需注意再融資壓力。</li><li><strong>淨債務/EBITDA</strong>：(14.25 億 - 12.28 億) / 30.91 億 (EBITDA = EBIT 26.70+折舊 7.16 億+攤銷 0.85 億) = 1.97/30.91 = 0.64 倍，槓桿水位極低。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>3 年期負債結構對比 (2022→2025)</strong>： 2022 年報總負債 338.16 億 (流動 153.74 億/非流動 184.44 億)，當時短期借款僅 3.77 億，長期借款 107.70 億，是景碩營運高峰期末。進入 2023 年產業景氣下行，短期借款攀升至約 15-20 億區間，反映營運資金壓力。至 2025 年報短期借款 30.53 億，長期借款 111.97 億，顯示管理層在景氣復甦初期階段性擴大了短天期融資。</p><p><strong>短期流動性核實</strong>： 2025 年報現金 122.81 億 vs 一年內到期的短期債務約 33 億 (含短期借款 30.53 億、租賃負債短期部分約 0.42 億)。現金覆蓋率 3.7 倍，短期清償壓力不大。但佔資產 25.14% 的流動負債合計 201.06 億中，應付帳款及其他應付款佔比約 50%，需關注供應鏈付款週期是否因擴產而緊縮。</p><p><strong>高息壓力測試</strong>： 假設利率上升 1% (100 bps)，以總有息債務 142.50 億計，年利息增加 1.425 億。稀釋後 EPS 影響約 -0.31 元 (以 4.57 億股計)，對 2025 年 EPS 3.51 元的衝擊約 8.8%，尚不構成致命威脅，但若升息 2% 則侵蝕將達 17.6%。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p><strong>華爾街空頭視角</strong>：</p><ol><li><strong>隱藏負債風險</strong>：非流動負債中「其他非流動負債」50.31 億 (主為淨確定福利負債及遞延所得稅)，這部分雖非付息債務，但長期資金佔用不可忽視。</li><li><strong>資本支出對槓桿的推升</strong>：2025 年購置固定資產 61.17 億，較 2024 年明顯擴張。ABF 載板擴產需大量資本投入，若營收復甦不如預期，負債比可能向 55% 逼近。</li><li><strong>利率敏感度</strong>：景碩平均借款利率約 2.75% (利息 3.91 億/平均有息負債約 142 億)。若全球利率不退，利息費用可能突破 5 億，ICR 將降至 5 倍左右，仍安全但緩衝收窄。</li><li><strong>再融資條件追蹤</strong>：2025 年舉借長期借款 17.55 億與償還 31.86 億，顯示管理層持續進行債務結構優化。須關注 2026 年 3 月現增 145 元募集 101.5 億後，負債結構將顯著改善。</li></ol><p><strong>結論</strong>：淨債務僅為 EBITDA 的 0.64 倍，現金充足，償債壓力輕。惟 2026 年成長加速期若客戶回款放緩，負債比仍有攀揚風險。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>FinMind 資產負債表查詢</strong>: <code>balance_sheet 3189 2023-01-01 2026-04-23 --df</code> (科目：ShorttermBorrowings, LongtermBorrowings, CurrentLiabilities, NoncurrentLiabilities, CashAndCashEquivalents)</li><li><strong>FinMind 綜合損益表查詢</strong>: <code>finance 3189 2023-01-01 2026-04-23 --df</code> (科目：OperatingIncome, Revenue)</li><li><strong>FinMind 現金流量表查詢</strong>: <code>cash_flow 3189 2023-01-01 2026-04-23 --df</code> (科目：InterestExpense, Depreciation, RepaymentOfLongTermDebt, ProceedsFromLongTermDebt, PropertyAndPlantAndEquipment)</li><li><strong>財報狗</strong>: 利息保障倍數與財務結構比率 (statementdog.com/analysis/3189)</li><li><strong>數據更新日期</strong>: 2025 年報 (2025-12-31 財務數據，發布於 2026 年 Q1)</li></ul>',17)])])}const p=n(o,[["render",i]]);export{h as __pageData,p as default};
